/* Unified linker script for all hybrid test fixtures.
 *
 * Load base: 0x00100000 (1 MiB into andes_ae350 DRAM).
 *
 * andes_ae350 memory map:
 *   DRAM : 0x00000000 .. 0x7FFFFFFF  (writable, executable)
 *   MROM : 0x80000000 .. 0x87FFFFFF  (read-only)
 *
 * Reserved scratch (below text, used by .S fixtures):
 *   0x00000004              rt_csr_survival mtvec test value
 *   0x00001000              semihost_exit.inc param block
 *   0x00002000              rt_all_gprs spill area
 *   0x00003000              rt_mem_loadstore / rt_unaligned_lh buffer
 *   0x00010000              rt_shared_mem 4 KB buffer
 *
 * Layout above 0x00100000:
 *   .text         pinned at 0x00100000 (entry _start)
 *   .rodata
 *   .data         _edata terminates .data
 *   .bss          _end   terminates .bss (crt0 zeros [.bss, _end))
 *   _stack        0x00700000 (used by crt0.S to init sp)
 *   V_SCRATCH     0x00FF0000 (reserved by v_regfile_xfer.{c,hpp})
 *
 * .S fixtures with no .data/.bss leave those sections empty (zero cost).
 * C fixtures rely on _edata / _end / _stack.
 */

ENTRY(_start)

SECTIONS {
    . = 0x00100000;

    .text : {
        *(.text.init)
        *(.text*)
    }

    .rodata : {
        *(.rodata*)
        *(.srodata*)
    }

    .data : {
        *(.data*)
        *(.sdata*)
    }
    _edata = .;

    .bss : {
        *(.bss*)
        *(.sbss*)
        *(COMMON)
    }
    _end = .;

    /* _stack sits well below V_SCRATCH (0x00FF0000) with ~9 MiB headroom.
     * Override at link time with -Wl,--defsym,_stack=... if needed. */
    PROVIDE(_stack = 0x00700000);
}
